"""Workflow scheduler — generated by doql.

Usage:
    python -m workflows.scheduler

Requires: pip install schedule
"""
import logging
import time

from workflows.engine import engine

# Import all workflows to register them
import workflows.wf_daily_overdue_check  # noqa: F401
import workflows.wf_inspection_fail_handling  # noqa: F401
import workflows.wf_annual_exercise_reminder  # noqa: F401
import workflows.wf_cylinder_filling_audit  # noqa: F401

logger = logging.getLogger("workflow.scheduler")

SCHEDULED_WORKFLOWS = [
    ("daily_overdue_check", "0 8 * * *"),
    ("annual_exercise_reminder", "0 9 1 1 *"),
    ("cylinder_filling_audit", "monthly"),
]


def run_scheduled():
    """Run all scheduled workflows (integrate with your cron/schedule library)."""
    for name, cron in SCHEDULED_WORKFLOWS:
        logger.info(f"Running scheduled workflow: {name} ({cron})")
        try:
            result = engine.run(name)
            logger.info(f"  Result: {result.status.value}")
        except Exception as e:
            logger.error(f"  Error: {e}")


if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO)
    run_scheduled()
